import React, { useState, useEffect } from 'react';
import { getAuditLogs } from '../services/userService';

const AuditLogs = () => {
    const [logs, setLogs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        const fetchLogs = async () => {
            try {
                const data = await getAuditLogs();
                setLogs(data);
            } catch (err) {
                setError('Failed to fetch audit logs. You may not have administrative permissions.');
            } finally {
                setLoading(false);
            }
        };
        fetchLogs();
    }, []);

    const formatTimestamp = (ts) => {
        try {
            return new Date(ts).toLocaleString();
        } catch {
            return ts;
        }
    };

    if (loading) return (
        <div className="flex justify-center items-center py-32">
            <div className="animate-spin h-8 w-8 border-4 border-indigo-500 border-t-transparent rounded-full shadow-lg shadow-indigo-500/20" />
        </div>
    );

    return (
        <div className="max-w-7xl mx-auto px-4 py-12">
            <div className="mb-10">
                <h1 className="text-3xl font-extrabold text-white">Audit Log Dashboard</h1>
                <p className="text-slate-500 text-sm mt-1">Review critical system events and security logs</p>
            </div>

            {error && <div className="alert-error mb-8 shadow-xl">{error}</div>}

            <div className="glass-card shadow-2xl overflow-hidden border border-white/5">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-white/5 border-b border-white/10">
                                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Timestamp</th>
                                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Operator</th>
                                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Action</th>
                                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Context Details</th>
                                <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Client IP</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {logs.map((log) => (
                                <tr key={log.id} className="hover:bg-white/5 transition-colors group">
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-300 font-medium">
                                        {formatTimestamp(log.timestamp)}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm">
                                        <span className="px-2 py-1 rounded-md bg-indigo-500/10 text-indigo-400 font-bold">
                                            {log.username}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-white font-semibold">
                                        {log.action}
                                    </td>
                                    <td className="px-6 py-4 text-sm text-slate-400 italic">
                                        {log.details || 'No additional context'}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm tabular-nums text-slate-500 font-mono">
                                        {log.ipAddress}
                                    </td>
                                </tr>
                            ))}
                            {logs.length === 0 && !error && (
                                <tr>
                                    <td colSpan="5" className="px-6 py-12 text-center text-slate-500 italic">
                                        No audit records found in the current log session.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default AuditLogs;
